CREATE TABLE IF NOT EXISTS `report_template` (
  `template_id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '模板ID',
  `template_name` varchar(100) NOT NULL COMMENT '模板名称',
  `template_type` int(11) NOT NULL COMMENT '模板类型：1-系统模板 2-自定义模板',
  `template_content` text NOT NULL COMMENT '模板内容',
  `template_desc` varchar(200) DEFAULT NULL COMMENT '模板描述',
  `status` int(11) NOT NULL COMMENT '状态：0-禁用 1-启用',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`template_id`),
  KEY `template_name` (`template_name`),
  KEY `status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8 COMMENT='测试报告模板表';

-- 插入默认模板
INSERT IGNORE INTO `report_template` (`template_id`, `template_name`, `template_type`, `template_content`, `template_desc`, `status`, `create_by`, `create_time`, `update_by`, `update_time`) VALUES
(1, '默认测试报告模板', 1, '<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n    <meta charset="UTF-8">\n    <title>测试报告</title>\n    <style>\n        body { font-family: Arial, sans-serif; margin: 20px; }\n        h1, h2 { color: #333; }\n        table { border-collapse: collapse; width: 100%; margin-top: 20px; }\n        th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }\n        th { background-color: #f2f2f2; }\n        .summary { background-color: #f9f9f9; padding: 15px; margin-bottom: 20px; border-radius: 5px; }\n        .success { color: green; }\n        .fail { color: red; }\n    </style>\n</head>\n<body>\n    <h1>测试报告</h1>\n    <div class="summary">\n        <h2>任务信息</h2>\n        <p><strong>任务名称：</strong>${taskName}</p>\n        <p><strong>任务状态：</strong>${taskStatus}</p>\n        <p><strong>创建时间：</strong>${createTime}</p>\n        <p><strong>完成时间：</strong>${finishTime}</p>\n    </div>\n    <div class="summary">\n        <h2>测试结果统计</h2>\n        <p><strong>总用例数：</strong>${caseTotalCount}</p>\n        <p><strong>成功数：</strong><span class="success">${caseSuccCount}</span></p>\n        <p><strong>失败数：</strong><span class="fail">${caseFailCount}</span></p>\n        <p><strong>锁定数：</strong>${caseLockCount}</p>\n        <p><strong>未执行数：</strong>${caseNoexecCount}</p>\n        <p><strong>成功率：</strong>${successRate}</p>\n    </div>\n    <h2>用例执行详情</h2>\n    <table>\n        <thead>\n            <tr>\n                <th>执行步骤</th>\n                <th>执行详情</th>\n                <th>日志级别</th>\n                <th>执行时间</th>\n            </tr>\n        </thead>\n        <tbody>\n            ${caseDetails}\n        </tbody>\n    </table>\n</body>\n</html>', '默认测试报告模板，包含任务信息、测试结果统计和用例执行详情', 1, 'admin', NOW(), 'admin', NOW()),
(2, '简洁测试报告模板', 1, '<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n    <meta charset="UTF-8">\n    <title>测试报告</title>\n    <style>\n        body { font-family: Arial, sans-serif; margin: 20px; }\n        h1 { color: #333; }\n        .stats { display: flex; gap: 20px; margin: 20px 0; }\n        .stat-item { background-color: #f2f2f2; padding: 15px; border-radius: 5px; flex: 1; }\n        .stat-value { font-size: 24px; font-weight: bold; }\n        .success { color: green; }\n        .fail { color: red; }\n    </style>\n</head>\n<body>\n    <h1>测试报告 - ${taskName}</h1>\n    <div class="stats">\n        <div class="stat-item">\n            <div>总用例数</div>\n            <div class="stat-value">${caseTotalCount}</div>\n        </div>\n        <div class="stat-item">\n            <div>成功数</div>\n            <div class="stat-value success">${caseSuccCount}</div>\n        </div>\n        <div class="stat-item">\n            <div>失败数</div>\n            <div class="stat-value fail">${caseFailCount}</div>\n        </div>\n        <div class="stat-item">\n            <div>成功率</div>\n            <div class="stat-value">${successRate}</div>\n        </div>\n    </div>\n    <p><strong>任务状态：</strong>${taskStatus}</p>\n    <p><strong>执行时间：</strong>${createTime} 至 ${finishTime}</p>\n</body>\n</html>', '简洁测试报告模板，只包含关键测试统计信息', 1, 'admin', NOW(), 'admin', NOW()),
(3, '详细测试报告模板', 1, '<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n    <meta charset="UTF-8">\n    <title>测试报告</title>\n    <style>\n        body { font-family: Arial, sans-serif; margin: 20px; }\n        h1, h2, h3 { color: #333; }\n        table { border-collapse: collapse; width: 100%; margin-top: 15px; }\n        th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }\n        th { background-color: #f2f2f2; }\n        .summary { background-color: #f9f9f9; padding: 15px; margin-bottom: 20px; border-radius: 5px; }\n        .section { margin-bottom: 30px; }\n        .success { color: green; }\n        .fail { color: red; }\n        .info { color: blue; }\n    </style>\n</head>\n<body>\n    <h1>详细测试报告</h1>\n    <div class="section">\n        <h2>任务信息</h2>\n        <div class="summary">\n            <p><strong>任务名称：</strong>${taskName}</p>\n            <p><strong>任务状态：</strong>${taskStatus}</p>\n            <p><strong>创建时间：</strong>${createTime}</p>\n            <p><strong>完成时间：</strong>${finishTime}</p>\n        </div>\n    </div>\n    <div class="section">\n        <h2>测试结果统计</h2>\n        <div class="summary">\n            <table>\n                <tr>\n                    <th>统计项</th>\n                    <th>数量</th>\n                    <th>占比</th>\n                </tr>\n                <tr>\n                    <td>总用例数</td>\n                    <td>${caseTotalCount}</td>\n                    <td>100%</td>\n                </tr>\n                <tr>\n                    <td>成功数</td>\n                    <td class="success">${caseSuccCount}</td>\n                    <td>${successRate}</td>\n                </tr>\n                <tr>\n                    <td>失败数</td>\n                    <td class="fail">${caseFailCount}</td>\n                    <td>${caseTotalCount > 0 ? (caseFailCount / caseTotalCount * 100).toFixed(2) + '%' : '0%'}</td>\n                </tr>\n                <tr>\n                    <td>锁定数</td>\n                    <td>${caseLockCount}</td>\n                    <td>${caseTotalCount > 0 ? (caseLockCount / caseTotalCount * 100).toFixed(2) + '%' : '0%'}</td>\n                </tr>\n                <tr>\n                    <td>未执行数</td>\n                    <td>${caseNoexecCount}</td>\n                    <td>${caseTotalCount > 0 ? (caseNoexecCount / caseTotalCount * 100).toFixed(2) + '%' : '0%'}</td>\n                </tr>\n            </table>\n        </div>\n    </div>\n    <div class="section">\n        <h2>用例执行详情</h2>\n        <table>\n            <thead>\n                <tr>\n                    <th>执行步骤</th>\n                    <th>执行详情</th>\n                    <th>日志级别</th>\n                    <th>执行时间</th>\n                </tr>\n            </thead>\n            <tbody>\n                ${caseDetails}\n            </tbody>\n        </table>\n    </div>\n    <div class="section">\n        <h2>测试总结</h2>\n        <div class="summary">\n            <p>本次测试共执行 ${caseTotalCount} 个用例，其中成功 ${caseSuccCount} 个，失败 ${caseFailCount} 个，成功率为 ${successRate}。</p>\n            <p>测试执行时间：${createTime} 至 ${finishTime}。</p>\n            <p>测试状态：${taskStatus}。</p>\n        </div>\n    </div>\n</body>\n</html>', '详细测试报告模板，包含任务信息、详细的测试结果统计、用例执行详情和测试总结', 1, 'admin', NOW(), 'admin', NOW());